+    host,
+    port: parseInt(process.env.RUVECTOR_PORT || process.env.PGPORT || '5432', 10),
+    database,
+    user,
+    password: password || '',
+    ssl: process.env.RUVECTOR_SSL === 'true',
+  };
+}
